import React, { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import api from '../utils/api';
import MLWagePrediction from '../components/MLWagePrediction';
import './PostJob.css';

const PostJob = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    location: {
      address: '',
      city: '',
      state: '',
      pincode: ''
    }
  });

  const [mlPrediction, setMlPrediction] = useState(null);

  // Handle location changes from ML prediction
  const handleLocationChange = (location) => {
    setFormData(prev => ({
      ...prev,
      location: {
        ...prev.location,
        city: location
      }
    }));
  };

  // Handle pre-filled category from navigation
  useEffect(() => {
    if (location.state?.selectedCategory) {
      // Job type is now handled by ML prediction, no need to set it here
      console.log(`đźŽŻ Category pre-selected: ${location.state.categoryName}`);
    }
  }, [location.state]);

  const handleChange = (e) => {
    const { name, value, type } = e.target;
    if (name.includes('.')) {
      const [parent, child] = name.split('.');
      setFormData({
        ...formData,
        [parent]: { ...formData[parent], [child]: value }
      });
    } else {
      setFormData({
        ...formData,
        [name]: type === 'number' ? parseInt(value) || value : value
      });
    }
  };

  const handleMLPredictionComplete = (prediction) => {
    setMlPrediction(prediction);
    // Auto-fill wage estimation based on ML prediction
    if (prediction && prediction.predicted_wage) {
      const dailyRate = prediction.predicted_wage;
      const totalEstimated = dailyRate * 1; // Default to 1 worker if workersNeeded is removed
      
      setFormData(prev => ({
        ...prev,
        wageCalculation: {
          ratePerDay: dailyRate,
          totalEstimated
        }
      }));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    try {
      // Include ML prediction in job data if available
      const jobData = {
        ...formData,
        mlPrediction: mlPrediction,
        wageCalculation: formData.wageCalculation || {
          ratePerDay: mlPrediction?.predicted_wage || 0,
          totalEstimated: formData.wageCalculation?.totalEstimated || 0
        }
      };

      console.log('đźš€ Posting job with data:', jobData);
      
      const response = await api.post('/jobs', jobData);
      
      if (response.data.success) {
        alert(`âś… Job posted successfully! 
        
đź“¬ Notifications sent to ${response.data.notifiedWorkers || 0} matching workers.
        
đźŽŻ Workers will be able to see and apply for this job immediately.`);
        
        // Log the workers who were notified
        if (response.data.notifiedWorkersList && response.data.notifiedWorkersList.length > 0) {
          console.log('đź“‹ Workers notified:', response.data.notifiedWorkersList);
        }
        
        navigate('/employer/dashboard');
      } else {
        alert('âťŚ ' + (response.data.message || 'Failed to post job'));
      }
    } catch (err) {
      console.error('đźš¨ Job posting error:', err);
      alert('âťŚ ' + (err.response?.data?.message || 'Failed to post job'));
    }
  };

  return (
    <div className="post-job-container">
      <h1>Post a New Job</h1>
      
      {/* Show pre-selected category indicator */}
      {location.state?.categoryName && (
        <div className="preselected-category">
          <span className="category-indicator">
            đźŽŻ Category: <strong>{location.state.categoryName}</strong>
          </span>
          <span className="category-hint">You can change this if needed</span>
        </div>
      )}
      <form onSubmit={handleSubmit} className="job-form">
        
        {/* ML Wage Prediction Component */}
        <MLWagePrediction 
          onPredictionComplete={handleMLPredictionComplete} 
          externalLocation={formData.location.city}
          onLocationChange={handleLocationChange}
        />

        <div className="form-grid">
          <div className="form-group">
            <label>Job Title</label>
            <input name="title" value={formData.title} onChange={handleChange} required placeholder="e.g. Need House Painting" />
          </div>
        </div>

        <div className="form-group">
          <label>Description</label>
          <textarea name="description" value={formData.description} onChange={handleChange} required rows="4" placeholder="Describe the work details..."></textarea>
        </div>

        <div className="form-section">
          <h3>Location Details</h3>
          <div className="form-grid">
            <input name="location.address" value={formData.location.address} onChange={handleChange} required placeholder="Address" />
            <input name="location.city" value={formData.location.city} onChange={handleChange} required placeholder="City" />
            <input name="location.state" value={formData.location.state} onChange={handleChange} required placeholder="State" />
            <input name="location.pincode" value={formData.location.pincode} onChange={handleChange} required placeholder="Pincode" />
          </div>
        </div>

        {mlPrediction && (
          <div className="estimation-card">
            <h3>đź’° Estimated Cost: â‚ą{formData.wageCalculation?.totalEstimated || 0}</h3>
            <div className="estimation-breakdown">
              <div className="breakdown-item">
                <span>Daily Rate (ML Predicted)</span>
                <span>â‚ą{mlPrediction.predicted_wage}</span>
              </div>
              <div className="breakdown-item">
                <span>Total Estimated Cost</span>
                <span>â‚ą{formData.wageCalculation?.totalEstimated || 0}</span>
              </div>
            </div>
            <p className="estimation-note">* This is an ML-based estimate. Actual rates may be negotiated with workers.</p>
          </div>
        )}

        <button type="submit" className="submit-btn">Post Job</button>
      </form>
    </div>
  );
};

export default PostJob;
